BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?ownedElem ?name ?type WHERE {
  ?elem vocab:NamedElement_name "Procedure%20Executive%20and%20Analysis%20Software" .
  ?elem vocab:Element_ownedElement ?ownedElem .
  ?ownedElem rdf:type ?type .
  OPTIONAL { ?ownedElem vocab:NamedElement_name ?name }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?port ?name ?type WHERE {
  ?elem vocab:NamedElement_name "Procedure%20Executive%20and%20Analysis%20Software" .
  ?elem vocab:EncapsulatedClassifier_ownedPort ?port .
  ?port rdf:type ?type .
  OPTIONAL { ?port vocab:NamedElement_name ?name }
}
LIMIT 30

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?attr ?name ?type WHERE {
  ?elem vocab:NamedElement_name "Procedure%20Executive%20and%20Analysis%20Software" .
  ?elem vocab:StructuredClassifier_ownedAttribute ?attr .
  ?attr rdf:type ?type .
  OPTIONAL { ?attr vocab:NamedElement_name ?name }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?attr ?name WHERE {
  ?elem vocab:NamedElement_name "Procedure%20Executive%20and%20Analysis%20Software" .
  ?elem rdf:type vocab:block .
  { ?elem vocab:Class_ownedAttribute__from_Class ?attr }
  UNION
  { ?elem vocab:Classifier_attribute ?attr }
  UNION
  { ?elem vocab:StructuredClassifier_ownedAttribute ?attr }
  ?attr vocab:NamedElement_name ?name .
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?spec ?constrained ?constrainedName WHERE {
  ?constraint vocab:Constraint_specification ?spec .
  ?constraint vocab:Constraint_constrainedElement ?constrained .
  OPTIONAL { ?constrained vocab:NamedElement_name ?constrainedName }
}
LIMIT 20

